// Entrée venant du Webhook (JSON)
const raw = items[0].json || {};

// Paramètres optionnels avec défauts
const scope = raw.scope || "tech_only";
const timeout = raw.timeout || 90;

// Tu pourrais plus tard ajouter d'autres filtres : since_days, sources, etc.

return [
  {
    json: {
      scope,
      timeout
    }
  }
];

// Réponse brute de l'API backend /tech/watch/latest
const resp = $json || {};

const status = resp.status || "unknown";
const count = resp.count ?? 0;
const items = Array.isArray(resp.items) ? resp.items : [];

// Petit comptage : Hot / Trending / Fresh
let hot = 0;
let trending = 0;
let fresh = 0;

for (const it of items) {
  const rl = String(it.rank_label || "");
  if (rl.startsWith("🔥")) hot++;
  else if (rl.startsWith("⭐")) trending++;
  else fresh++;
}

// Métriques pour le radar
const sourcesTotal = count;
const nbOk = count;          // toutes les entrées chargées correctement
const nbErr = 0;             // les erreurs sont filtrées côté backend
const sourcesOk = count;
const sourcesError = 0;
const duration = resp.duration || null;   // peut être null ici
const truncated = false;                  // /latest renvoie l'état courant

// Déduire un niveau de qualité global
let quality = "Inconnu";
if (status === "ok" && sourcesTotal > 0) {
  quality = "✅ Complet";
} else if (status === "ok" && sourcesTotal === 0) {
  quality = "⚠️ Vide";
} else if (status === "error") {
  quality = "❌ Échec";
}

// Construire un petit résumé texte
let headline = "Etat de la veille inconnu.";
if (sourcesTotal > 0) {
  headline = `Veille chargée : ${sourcesOk}/${sourcesTotal} sources actives.`;
  if (hot > 0 || trending > 0) {
    headline += ` ${hot} Hot · ${trending} Trending.`;
  }
}

// On renvoie un JSON propre, prêt pour StormCopilot
return [
  {
    json: {
      type: "tech_radar",
      status,
      quality,
      headline,
      metrics: {
        nb_ok: nbOk,
        nb_err: nbErr,
        sources_total: sourcesTotal,
        sources_ok: sourcesOk,
        sources_error: sourcesError,
        duration_sec: duration,
        truncated,
        hot,
        trending,
        fresh
      },
      fetched_at: new Date().toISOString(),
      raw: resp
    }
  }
];
